class Solution:
    def colorGrid(self, n, m, sources):
        grid = [[0] * m for _ in range(n)]
        for r, c, color in sources:
            grid[r][c] = color
        dirs = [(-1, 0), (1, 0), (0, -1), (0, 1)]
        changed = True
        while changed:
            changed = False
            new_grid = [row[:] for row in grid]
            for r in range(n):
                for c in range(m):
                    if grid[r][c] == 0:
                        best = 0
                        for dr, dc in dirs:
                            nr, nc = r + dr, c + dc
                            if 0 <= nr < n and 0 <= nc < m and grid[nr][nc] != 0:
                                if grid[nr][nc] > best:
                                    best = grid[nr][nc]
                        if best:
                            new_grid[r][c] = best
                            changed = True
            grid = new_grid
        return grid

