class Solution:
    def colorGrid(self, n, m, sources):
        grid = [[0] * m for _ in range(n)]
        frontier = []
        for r, c, color in sources:
            grid[r][c] = color
            frontier.append((r, c))
        dirs = [(-1, 0), (1, 0), (0, -1), (0, 1)]
        while frontier:
            next_colors = {}
            for r, c in frontier:
                color = grid[r][c]
                for dr, dc in dirs:
                    nr, nc = r + dr, c + dc
                    if 0 <= nr < n and 0 <= nc < m and grid[nr][nc] == 0:
                        cur = next_colors.get((nr, nc))
                        if cur is None or color > cur:
                            next_colors[(nr, nc)] = color
            if not next_colors:
                break
            for (nr, nc), color in next_colors.items():
                grid[nr][nc] = color
            frontier = list(next_colors.keys())
        return grid

