var colorGrid = function(n, m, sources) {
    const grid = [];
    for (let r = 0; r < n; r++) grid.push(new Array(m).fill(0));
    let frontier = [];
    for (const [r, c, color] of sources) {
        grid[r][c] = color;
        frontier.push([r, c]);
    }
    const dirs = [[-1, 0], [1, 0], [0, -1], [0, 1]];
    while (frontier.length > 0) {
        const nextColors = new Map();
        for (const [r, c] of frontier) {
            const color = grid[r][c];
            for (const [dr, dc] of dirs) {
                const nr = r + dr, nc = c + dc;
                if (nr >= 0 && nr < n && nc >= 0 && nc < m && grid[nr][nc] === 0) {
                    const key = nr * m + nc;
                    const cur = nextColors.get(key);
                    if (cur === undefined || color > cur) {
                        nextColors.set(key, color);
                    }
                }
            }
        }
        if (nextColors.size === 0) break;
        const nextFrontier = [];
        for (const [key, color] of nextColors) {
            const r = Math.floor(key / m), c = key % m;
            grid[r][c] = color;
            nextFrontier.push([r, c]);
        }
        frontier = nextFrontier;
    }
    return grid;
};
